def token_case(s):
    tokens = s.split('_')
    exceptions = ['URL', 'ID']
    result = []

    for i, token in enumerate(tokens):
        if token in exceptions:
            result.append(token)
        elif i == 0:
            result.append(token.lower())
        else:
            result.append(token.capitalize())

    return ''.join(result)

# Edge Case: Leading underscore
print(token_case('_leading_underscore'))  # Output: 'leading_underscore'
